query:
SELECT 
  COUNT(*) as total,
  SUM(CASE WHEN imageUrl IS NOT NULL AND imageUrl != '' THEN 1 ELSE 0 END) as com_imagem,
  SUM(CASE WHEN imageUrl IS NULL OR imageUrl = '' THEN 1 ELSE 0 END) as sem_imagem
FROM players;

-- Mostrar alguns com imagem para confirmar que a URL está correta
SELECT name, imageUrl FROM players WHERE imageUrl IS NOT NULL AND imageUrl != '' LIMIT 5;

-- Mostrar alguns sem imagem
SELECT name, club, overall FROM players WHERE imageUrl IS NULL OR imageUrl = '' ORDER BY overall DESC LIMIT 10;

